import asyncio
import websockets
import json
from collections import defaultdict

class GameServer:
    def __init__(self):
        self.connected_players = {}
        self.inventories = defaultdict(list)
        self.lock = asyncio.Lock()

    async def handle_connection(self, websocket, path):
        player_id = await websocket.recv()
        self.connected_players[player_id] = websocket
        try:
            async for message in websocket:
                data = json.loads(message)
                if data['action'] == 'trade':
                    await self.handle_trade(data['from'], data['to'], data['item'])
        finally:
            del self.connected_players[player_id]

    async def handle_trade(self, from_player, to_player, item):
        async with self.lock:
            if item in self.inventories[from_player]:
                self.inventories[from_player].remove(item)
                self.inventories[to_player].append(item)
                await self.notify_player(from_player, f"Traded {item} to {to_player}")
                await self.notify_player(to_player, f"Received {item} from {from_player}")

    async def notify_player(self, player_id, message):
        if player_id in self.connected_players:
            await self.connected_players[player_id].send(json.dumps({'message': message}))

    async def start_server(self):
        async with websockets.serve(self.handle_connection, "localhost", 8765):
            await asyncio.Future()

if __name__ == "__main__":
    server = GameServer()
    asyncio.run(server.start_server())